from azure.storage.blob import BlobServiceClient
import uuid
import json
from datetime import datetime

import azure.functions as func


def main(file: func.InputStream,
          context: func.Context):

    # Get the connection string for Cosmos DB, and the file name
    config = parse_config()
    connstr = config['CosmosDBConnectionString']
    containername = 'Documents'
    filename = config['FileName']

    try:
        # 1. Connect to blob storage with SAS
        sas = get_file(config['StorageConnectionString'],
                       config["ContainerName"], filename)

        if len(sas) == 0:
            return False, 'SAS token empty', None

        # Connect to Blobs
        client = BlobServiceClient.from_connection_string(config[
                                                "StorageConnectionString"])
        containerClient = client.get_container_client("invoicereader")

        blockblob_properties = containerClient.create_blob_from_stream(
                            "rawdata", filename, sas)
        print(blockblob_properties)

    except Exception as e:
        return False, str(e), None
    else:
        try:
            # Connect to Cosmos DB and write data to the 'Documents' collection
            from azure.cosmos import exceptions

            db = connectCosmosDB(connstr)['database']
            container = connectCosmosDB(
                connstr)[db][config["containerName"]]

            file_data = {
                "id": str(uuid.uuid4()),
                "fileName": filename,
                "fileDate": datetime.utcnow().isoformat(),
                'rawData': sas
            }
        except exceptions.CosmosHttpResponseError as e:
            return False, json.dumps(e), None

        try:
            container.create_item(file_data)
        # Handle a potential conflict, which will happen when we are adding the same file more than once.
        except exceptions.CosmosItemExistsError as e:
            print('CosmosItemExistsError. We expected the item to exist.')

    return True, 'File processed', True